import{_ as a,o as r,c as o,ae as t}from"./chunks/framework.9mFzz-eW.js";const f=JSON.parse('{"title":"core/api-proxy","description":"","frontmatter":{},"headers":[],"relativePath":"api/core.api-proxy.md","filePath":"api/core.api-proxy.md"}'),c={name:"api/core.api-proxy.md"};function i(l,e,n,p,d,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="core-api-proxy" tabindex="-1">core/api-proxy <a class="header-anchor" href="#core-api-proxy" aria-label="Permalink to &quot;core/api-proxy&quot;">​</a></h1><p>Proxy 기반 도메인 객체 변경 추적 엔진</p><p><code>createProxy()</code>는 순수 JS 객체를 ES6 <code>Proxy</code>로 감싸 <code>set</code> / <code>get</code> / <code>deleteProperty</code> 트랩으로 모든 필드 변경을 자동으로 기록한다.</p><h2 id="주요-설계-원칙" tabindex="-1">주요 설계 원칙 <a class="header-anchor" href="#주요-설계-원칙" aria-label="Permalink to &quot;주요 설계 원칙&quot;">​</a></h2><h3 id="_1-lazy-proxying-weakmap-캐싱-refactor-core-engine-2026-03-18" tabindex="-1">1. Lazy Proxying &amp; WeakMap 캐싱 (refactor/core-engine, 2026-03-18) <a class="header-anchor" href="#_1-lazy-proxying-weakmap-캐싱-refactor-core-engine-2026-03-18" aria-label="Permalink to &quot;1. Lazy Proxying &amp; WeakMap 캐싱 (refactor/core-engine, 2026-03-18)&quot;">​</a></h3><p>중첩 객체에 접근할 때마다 새 <code>Proxy</code>를 생성하면 V8 GC에 막대한 부하를 준다. <code>proxyCache(WeakMap)</code>을 사용해 동일한 원본 객체에 대한 <code>Proxy</code>를 캐싱하고, 원본 객체가 GC 대상이 될 때 <code>Proxy</code>도 함께 수거된다.</p><h3 id="_2-reflect-api-전면-적용-refactor-core-engine-2026-03-18" tabindex="-1">2. Reflect API 전면 적용 (refactor/core-engine, 2026-03-18) <a class="header-anchor" href="#_2-reflect-api-전면-적용-refactor-core-engine-2026-03-18" aria-label="Permalink to &quot;2. Reflect API 전면 적용 (refactor/core-engine, 2026-03-18)&quot;">​</a></h3><p>트랩 내부의 모든 속성 접근을 <code>target[prop]</code> 직접 접근 대신 <code>Reflect.get / Reflect.set / Reflect.deleteProperty</code>로 처리하여 프로토타입 체인과 <code>this</code> 바인딩이 복잡한 객체에서의 컨텍스트 소실을 방지한다.</p><h3 id="_3-배열-변이-메서드-delta-최적화-refactor-array-patch-optimization-2026-03-18" tabindex="-1">3. 배열 변이 메서드 Delta 최적화 (refactor/array-patch-optimization, 2026-03-18) <a class="header-anchor" href="#_3-배열-변이-메서드-delta-최적화-refactor-array-patch-optimization-2026-03-18" aria-label="Permalink to &quot;3. 배열 변이 메서드 Delta 최적화 (refactor/array-patch-optimization, 2026-03-18)&quot;">​</a></h3><p><code>ON_MUTATIONS</code>(<code>shift</code>, <code>unshift</code>, <code>splice</code>, <code>sort</code>, <code>reverse</code>) 호출 시 set 트랩을 뮤트(mute)하고 변경된 인덱스 범위만 수학적으로 계산하여 정확한 RFC 6902 JSON Patch 연산(<code>ADD</code> / <code>REMOVE</code> / <code>REPLACE</code>)으로 기록한다.</p><h2 id="반환값-—-도개교-drawbridge-세트" tabindex="-1">반환값 — &quot;도개교(Drawbridge)&quot; 세트 <a class="header-anchor" href="#반환값-—-도개교-drawbridge-세트" aria-label="Permalink to &quot;반환값 — &quot;도개교(Drawbridge)&quot; 세트&quot;">​</a></h2><p><code>{ proxy, getChangeLog, getTarget, clearChangeLog }</code> 네 클로저를 <code>DomainState</code>가 보관하며, 외부에는 <code>proxy</code>만 공개된다.</p><h2 id="changelog-항목-구조-rfc-6902-기반" tabindex="-1">changeLog 항목 구조 (RFC 6902 기반) <a class="header-anchor" href="#changelog-항목-구조-rfc-6902-기반" aria-label="Permalink to &quot;changeLog 항목 구조 (RFC 6902 기반)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{ op: &#39;add&#39;|&#39;replace&#39;|&#39;remove&#39;, path: &#39;/field/0&#39;, oldValue?, newValue? }</span></span></code></pre></div><h2 id="see" tabindex="-1">See <a class="header-anchor" href="#see" aria-label="Permalink to &quot;See&quot;">​</a></h2><ul><li><a href="https://www.rfc-editor.org/rfc/rfc6902" target="_blank" rel="noreferrer">RFC 6902 — JSON Patch</a></li><li><a href="https://developer.mozilla.org/ko/docs/Web/JavaScript/Reference/Global_Objects/Proxy" target="_blank" rel="noreferrer">MDN — Proxy</a></li></ul><h2 id="type-aliases" tabindex="-1">Type Aliases <a class="header-anchor" href="#type-aliases" aria-label="Permalink to &quot;Type Aliases&quot;">​</a></h2><ul><li><a href="./core.api-proxy.TypeAlias.ArrayMutationResult.html">ArrayMutationResult</a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><ul><li><a href="./core.api-proxy.Function.createProxy.html">createProxy</a></li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><h3 id="changelogentry" tabindex="-1">ChangeLogEntry <a class="header-anchor" href="#changelogentry" aria-label="Permalink to &quot;ChangeLogEntry&quot;">​</a></h3><p>Re-exports <a href="./core.api-mapper.Interface.ChangeLogEntry.html">ChangeLogEntry</a></p><hr><h3 id="onmutatecallback" tabindex="-1">OnMutateCallback <a class="header-anchor" href="#onmutatecallback" aria-label="Permalink to &quot;OnMutateCallback&quot;">​</a></h3><p>Re-exports <a href="./core.api-mapper.TypeAlias.OnMutateCallback.html">OnMutateCallback</a></p><hr><h3 id="proxywrapper" tabindex="-1">ProxyWrapper <a class="header-anchor" href="#proxywrapper" aria-label="Permalink to &quot;ProxyWrapper&quot;">​</a></h3><p>Re-exports <a href="./core.api-mapper.Interface.ProxyWrapper.html">ProxyWrapper</a></p>',29)])])}const u=a(c,[["render",i]]);export{f as __pageData,u as default};
